import json
import boto3
import os
import logging
from datetime import datetime, timezone
import uuid

logging.basicConfig(level=logging.INFO)
sqs = boto3.client('sqs')
COMMAND_QUEUE_URL = os.getenv('COMMAND_QUEUE_URL')
if not COMMAND_QUEUE_URL:
    # Fail fast during Lambda init so misconfiguration is obvious
    raise RuntimeError('Missing required environment variable: COMMAND_QUEUE_URL')

def lambda_handler(event, context):
    """
    Lambda API parancsok küldéséhez a robot felé
    POST /command
    """

    try:
        # CORS preflight
        if event.get('httpMethod') == 'OPTIONS':
            return {
                'statusCode': 204,
                'headers': {
                    'Access-Control-Allow-Origin': '*',
                    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
                    'Access-Control-Allow-Headers': 'Content-Type'
                },
                'body': ''
            }

        # Parse request body
        if 'body' not in event:
            return error_response(400, 'Missing request body')

        body = json.loads(event['body']) if isinstance(event['body'], str) else event['body']

        # Validate command
        if 'command' not in body:
            return error_response(400, 'Missing command field')

        command = body['command']

        if not isinstance(command, dict):
            return error_response(400, 'command must be an object')

        # Parancs üzenet összeállítása
        message = {
            'command': command,
            'timestamp': datetime.now(timezone.utc).isoformat(),
            'messageId': str(uuid.uuid4()),
            'source': 'dashboard'
        }

        # Opcionális metaadatok
        if 'metadata' in body:
            message['metadata'] = body['metadata']

        logging.info("Sending command to robot: %s", json.dumps(command))

        # SQS-be küldés
        response = sqs.send_message(
            QueueUrl=COMMAND_QUEUE_URL,
            MessageBody=json.dumps(message),
            MessageAttributes={
                'CommandType': {
                    'StringValue': command.get('action', 'unknown'),
                    'DataType': 'String'
                },
                'Priority': {
                    'StringValue': str(command.get('priority', 'normal')),
                    'DataType': 'String'
                }
            }
        )

        logging.info("Command sent successfully. MessageId: %s", response.get('MessageId'))

        return success_response({
            'success': True,
            'message': 'Command sent to robot',
            'messageId': response['MessageId'],
            'queueMessageId': response['MessageId'],
            'command': command,
            'timestamp': message['timestamp']
        })

    except json.JSONDecodeError as e:
        return error_response(400, f'Invalid JSON: {str(e)}')

    except Exception as e:
        logging.exception('Error in lambda_handler')
        return error_response(500, f'Internal error: {str(e)}')


def lambda_handler_get_status(event, context):
    """
    GET /command/status - Queue státusz lekérése
    """
    try:
        # Queue attribútumok lekérése
        response = sqs.get_queue_attributes(
            QueueUrl=COMMAND_QUEUE_URL,
            AttributeNames=[
                'ApproximateNumberOfMessages',
                'ApproximateNumberOfMessagesNotVisible',
                'ApproximateNumberOfMessagesDelayed'
            ]
        )

        attributes = response.get('Attributes', {})

        return success_response({
            'success': True,
            'queue': {
                'url': COMMAND_QUEUE_URL,
                'pendingMessages': int(attributes.get('ApproximateNumberOfMessages', 0)),
                'inFlightMessages': int(attributes.get('ApproximateNumberOfMessagesNotVisible', 0)),
                'delayedMessages': int(attributes.get('ApproximateNumberOfMessagesDelayed', 0))
            }
        })

    except Exception as e:
        logging.exception('Error getting queue status')
        return error_response(500, f'Error: {str(e)}')


def success_response(data, status_code=200):
    """Success response helper"""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type'
        },
        'body': json.dumps(data)
    }


def error_response(status_code, message):
    """Error response helper"""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*'
        },
        'body': json.dumps({
            'success': False,
            'error': message
        })
    }

import json
import boto3
import os
import logging
from datetime import datetime, timedelta, timezone

logging.basicConfig(level=logging.INFO)
s3 = boto3.client('s3')
bucket_name = os.getenv('S3_BUCKET_NAME')
if not bucket_name:
    raise RuntimeError('Missing required environment variable: S3_BUCKET_NAME')

def lambda_handler(event, context):
    """
    Lambda API a robot logok olvasásához S3-ból
    """

    try:
        # CORS preflight
        if event.get('httpMethod') == 'OPTIONS':
            return {
                'statusCode': 204,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*',
                    'Access-Control-Allow-Methods': 'GET, OPTIONS',
                    'Access-Control-Allow-Headers': 'Content-Type'
                },
                'body': ''
            }

        # Query paraméterek
        query_params = event.get('queryStringParameters', {}) or {}
        limit = int(query_params.get('limit', 50))
        date_filter = query_params.get('date', datetime.utcnow().strftime('%Y/%m/%d'))

        logging.info("Reading logs from s3://%s/robot-data/%s/", bucket_name, date_filter)

        # S3 objektumok listázása
        prefix = f"robot-data/{date_filter}/"

        response = s3.list_objects_v2(
            Bucket=bucket_name,
            Prefix=prefix,
            MaxKeys=limit
        )

        logs = []

        # Objektumok olvasása
        for obj in response.get('Contents', [])[:limit]:
            key = obj['Key']

            try:
                # Fájl tartalmának olvasása
                file_obj = s3.get_object(Bucket=bucket_name, Key=key)
                content = file_obj['Body'].read().decode('utf-8')
                try:
                    log_data = json.loads(content)
                except Exception:
                    log_data = {'data': content, 'timestamp': '', 'message_id': ''}

                # Hozzáadás a listához
                logs.append({
                    'key': key,
                    'timestamp': log_data.get('timestamp', ''),
                    'data': log_data.get('data', {}),
                    'message_id': log_data.get('message_id', ''),
                    'size': obj['Size'],
                    'last_modified': obj['LastModified'].isoformat()
                })

            except Exception as e:
                logging.exception('Error reading %s', key)
                continue

        # Legfrissebb előre rendezés
        logs.sort(key=lambda x: x['timestamp'], reverse=True)

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*',
                'Access-Control-Allow-Methods': 'GET, OPTIONS',
                'Access-Control-Allow-Headers': 'Content-Type'
            },
            'body': json.dumps({
                'success': True,
                'count': len(logs),
                'logs': logs,
                'bucket': bucket_name,
                'date': date_filter
            })
        }

    except Exception as e:
        logging.exception('Error in read_logs')
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': str(e)
            })
        }

